<script>
    $(document).ready(function () {

        // ================= PATIENT SEARCH =================
        $(""#SearchPatient"").keyup(function () {
            var search = $(this).val();

            if (search.length < 3) {
                $(""#patientResult"").hide();
                return;
            }

            $.ajax({
                url: '/Patient/SearchPatient',
                type: 'GET',
                data: { search: search },
                success: function (res) {

                    $(""#patientResult"").empty();

                    if (!res || res.length === 0) {
                        $(""#patientResult"")
                            .append('<li class=""list-group-item text-danger"">Patient not found</li>')
                            .show();
                        return;
                    }

                    $.each(res, function (i, item) {
                        $(""#patientResult"").append(`
                            <li class=""list-gr");
            WriteLiteral(@"oup-item patient-item""
                                data-id=""${item.id}""
                                data-name=""${item.FirstName} ${item.LastName}""
                                data-mobile=""${item.PhoneNumber}"">
                                <strong>${item.PhoneNumber}</strong> - ${item.FirstName} ${item.LastName}
                            </li>
                        `);
                    });

                    $(""#patientResult"").show();
                }
            });
        });

        // ================= SELECT PATIENT =================
        $(document).on(""click"", "".patient-item"", function () {
            $(""#PatientId"").val($(this).data(""id""));
            $(""#PatientName"").val($(this).data(""name""));
            $(""#MobileNo"").val($(this).data(""mobile""));
            $(""#patientResult"").hide();
        });

        // ================= SUBMIT VALIDATION =================
        $(""#appointmentForm"").submit(function (e) {

            if ($(""#Patient");
            WriteLiteral(@"Id"").val() == """" || $(""#PatientId"").val() == ""0"") {
                alert(""Please select patient"");
                e.preventDefault();
                return;
            }

            if ($(""#DoctorId"").val() == """") {
                alert(""Please select doctor"");
                e.preventDefault();
                return;
            }
        });

        // ================= CLICK OUTSIDE =================
        $(document).click(function (e) {
            if (!$(e.target).closest(""#SearchPatient"").length) {
                $(""#patientResult"").hide();
            }
        });

    });
</script>
");
